var suggestions,search;window.addEventListener('DOMContentLoaded',()=>{const a=new IntersectionObserver(a=>{a.forEach(a=>{const b=a.target.getAttribute('id');a.intersectionRatio>0?document.querySelector(`#TableOfContents a[href="#${b}"]`).classList.add('side-active'):document.querySelector(`#TableOfContents a[href="#${b}"]`).classList.remove('side-active')})});toc=document.querySelectorAll('#TableOfContents a'),toc.forEach(function(b){var c=b.getAttribute("href"),d=document.querySelector(c);a.observe(d)})}),suggestions=document.getElementById('suggestions'),search=document.getElementById('search'),search!==null&&document.addEventListener('keydown',inputFocus);function inputFocus(a){a.ctrlKey&&a.key==='/'&&(a.preventDefault(),search.focus()),a.key==='Escape'&&(search.blur(),suggestions.classList.add('d-none'))}document.addEventListener('click',function(a){var b=suggestions.contains(a.target);b||suggestions.classList.add('d-none')}),document.addEventListener('keydown',suggestionFocus);function suggestionFocus(c){const d=suggestions.classList.contains('d-none');if(d)return;const a=[...suggestions.querySelectorAll('a')];if(a.length===0)return;const b=a.indexOf(document.activeElement);if(c.key==="ArrowUp"){c.preventDefault();const d=b>0?b-1:0;a[d].focus()}else if(c.key==="ArrowDown"){c.preventDefault();const d=b+1<a.length?b+1:b;a[d].focus()}}(function(){var a=new FlexSearch.Document({tokenize:"forward",cache:100,document:{id:'id',store:["href","title","description"],index:["title","description"]}});a.add({id:0,href:"/ml/intro_dl/neural-networks/week1/",title:"Week 1 — Neural Networks and Deep Learning",description:"Introduction to Neural Networks",content:"Notations (source) :\n    Week 1 — Introduction to Deep Learning # May 1, 2021\nWelcome #  AI (Artificial Intelligence) is the new Electricity to bring about a change and a new era Parts of this course:  Neural Networks and Deep Learning. → Recognizing cats Improving Deep Neural Networks: Hyperparmeter tuning, Regularization and Optimization Structuring your Machine Learning Project → Best Practices for project Convolutional Neural Networks Natural Language Processing: Building sequence models    Introduction to Deep Learning # What is neural networks? # Neural networks are created by structuring layers, with each layer consisting of \u0026ldquo;neurons\u0026rdquo; which get activated depending on its activation function and the input.\nSupervised Learning with Neural Networks # Supervised learning refers to problems when we have inputs as well as labels (outputs) to predict using machine learning techniques. Then the models figure out the mapping from inputs to output.\nThe data can be:\n Structured Data (tables) Unstructured Data (images, audio, etc.)  Why is Deep Learning taking off? # Three reasons:\n Backpropagation algorithm Glorot and He initialization ReLU (Rectified Linear Unit) activation function  Other reasons:\n Data Computation power Algorithms  The scale at which we creating data is also important, as neural networks performance don\u0026rsquo;t stagnant unlike traditional machine learning algorithms\nIn this course $m$ denotes no of training examples.\nAbout this Course #  Week 1: Introduction Week 2: Basics of Neural Network programming Week 3: One hidden layer Neural Networks Week 4: Deep Neural Networks    Note\nAny image used here for illustration if not mentioned, is attributed to Andrew Ng\u0026rsquo;s lecture slides.    "}).add({id:1,href:"/ml/intro_dl/neural-networks/week2/",title:"Week 2 — Basics of Neural Network programming",description:"Basics of neural networks",content:"May 1, 2021\nLogistic Regression as a Neural Network #  Logistic Regression is an algorithm for Binary Classification.  Consider we have an image we want to classify as cat or not of 64x64 dimension\n   The images are stored as matrix pixel intensity value for different color channels. (one matrix per color channel and with each layer dimension being the dimension of image).\nTo represent image we can use a single feature vector:\n  So $n_x$ (input size) becomes $64\\times64\\times3 = 122288$.\n $$ x = \\begin{bmatrix} 255 \\\\ 231 \\\\...\\\\255\\\\134\\\\...\\\\255\\\\134\\\\93 \\end{bmatrix} $$  Notations:\n Logistic Regression # In formal terms for cat classification problem:\nGiven $x$, want $\\hat{y} = \\text{P}(y=1|x)$.\nwhere,\n $x \\in \\mathbb{R}^{n_x}$  Parameters: $w\\in \\mathbb{R}^{n_x}, b\\in \\mathbb{R}$\nOutput or Activation function # Output : $\\hat{y} = \\sigma(w^\\intercal x + b)$\nwhere,\n $$ \\sigma(Z) = \\frac{1}{1+ e^{-z}} \\\\[10pt] z = w^\\intercal + b $$   Exponential function $y = e^x$ (source: Wikipedia)\n  Hence, this satisfy the the two conditions:\nIf $z$ is large:\n$$ \\sigma(z) \\approx \\frac{1}{1+0} = 1 $$\nIf z is large negative number then, the exponential function returns very big value.\n$$ \\sigma(z) \\approx \\frac{1}{1+bigno} \\approx 0 $$\n   In a alternate notation you might see (like in Hands-on machine learning book) $\\hat{y} = \\sigma(x^{\\intercal}\\theta)$ instead of $\\sigma(w^\\intercal x + b)$. In this notation $\\theta_0$ represent bias vector and rest of the $\\theta$ vector contains the weights.    But in this course we will not be using this convention.\nLogistic Regression Cost Function #  Cost function (loss function for single training example) to optimize, want to be as small as possible. The Loss function is cost function averaged for all training instances.  $$ J(w, b)=J(\\theta) = -\\frac{1}{m}\\sum^m_{i=1}\\bigg[y^{(i)}\\log\\Big(\\hat{y}^{(i)}\\Big)+ \\Big(1-y^{(i)}\\Big)\\log\\Big(1-\\hat{y}^{(i)}\\Big)\\bigg] $$\n  The cost function for single training example, we want:   $$ c(\\theta) = \\begin{cases}-\\log(\\hat{y}) \u0026 \\text{if}\\enspace y=1\\\\-\\log(1-\\hat{y}) \u0026 \\text{if}\\enspace y=0\\end{cases} $$ ​  That means  If label is 1, we want $(-\\log(\\hat{y}))$ to be as small as possible $\\rightarrow$ want $(\\log\\hat{y})$ to be large as possible $\\rightarrow$ want $\\hat{y}$ to be large (i.e. $\\approx 1$). If label is 0, we want $(-\\log(1- \\hat{y}))$ to be as small as possible $\\rightarrow$ want $(\\log1-\\hat{y})$ to be large $\\rightarrow$ want $\\hat{y}$ to be small.    Gradient Descent # May 2, 2021\nGradient Descent is a generic optimization algorithm capable of finding optimal solutions to a wide range of problems, The general idea of Gradient Descent is to tweak parameters iteratively to minimize cost function.\nWe have a cost function for logistic regression.\n$$ J(w, b)=J(\\theta) = -\\frac{1}{m}\\sum^m_{i=1}\\bigg[y^{(i)}\\log\\Big(\\hat{y}^{(i)}\\Big)+ \\Big(1-y^{(i)}\\Big)\\log\\Big(1-\\hat{y}^{(i)}\\Big)\\bigg] $$\nWhere.\n $\\alpha$ is a hyperparmeter for learning rate. Derivative tells the slope of the function OR how a small change in a value what change comes to the function. On the left side the derivative (slope) will be negative making us increasing the weights. On the right side the derivative (slope) will be positive which will result in decreasing the weights.    So we will update the weights and bias like this:  $$ w = w - \\alpha\\frac{\\partial J(w,b)}{\\partial w} $$\n$$ b = b - \\alpha \\frac{\\partial J(w, b)}{\\partial b} $$\n  Tip: Remember $d$ is used for derivative whereas $\\partial$ is used to denote partial derivative when the function we want to derivate has multiple other variables (which are considered constant at the time we are finding the derivative).    Derivatives #   Computation Graph # A computational graph is defined as a directed graph where the nodes correspond to mathematical operations. Computational graphs are a way of expressing and evaluating a mathematical expression.\n The computation graph explains why the computations of neural network is organised with first a forward pass and then a backward pass in Backpropagation algorithm. Reverse-mode autodiff performs a forward pass through a computation graph, computing every node\u0026rsquo;s value for the current training batch, and then it performs a reverse pass, computing all the gradients at once. Let\u0026rsquo;s say we have a function  $$ J(a, b, c) = 3(a + bc) $$\n  In this we have 3 steps (represented by nodes) to compute. These are:\n$u = bc$\n$v = a+u$\n$J = 3v$\n   The blue arrows represent the forward pass and Red arrows the Backward pass\n  Computing with a computation Graph # {{ figure src=\u0026quot;/images/ml/intro_dl/neural_networks/0006.png\u0026quot; }}\n Let\u0026rsquo;s say we want to compute the derivative of $J$ with respect to $v$. $\\frac{dJ}{dv} = ?$ i.e. for a little change in $v$ how the value of $J$ changes? We know from our calculus class, the derivative should be:  $$ \\frac{dJ}{dv} = \\bold{3} $$\n  Then we want to compute the derivative of $J$ with respect to $a$. We can use chain rule which says:\nIf $a$ affects $v$ affects $J$ ($a \\rightarrow v \\rightarrow J$) then the amounts that $J$ changes when you nudge $a$ is the product of how much $v$ changes when you nudge $a$ times how much $J$ changes when you nudge $v$.\n   $$ \\frac{dv}{da} = \\bold{1} \\\\ [10pt] \\frac{dJ}{da} = \\frac{dJ}{dv}\\frac{dv}{da} = 3 \\times 1 = \\bold{3} $$   This illustrates how computing $$\\frac{dJ}{dv}$$ let\u0026rsquo;s us compute $$\\frac{dJ}{da}$$. In the code we will be using dvar to represent the the derivative of the final output variable with respect to any variable var. Let\u0026rsquo;s do it for other variables. What is the derivative of $J$ with respect to $u$.  $$ \\frac{dJ}{du} = \\frac{dJ}{dv}\\frac{dv}{du} = 3 \\times 1 = \\bold{3} $$\n And then derivative of $J$ with respect to $b$  $$ \\frac{du}{db} = 2 $$\n$$ \\frac{dJ}{db} = \\frac{dJ}{du}\\frac{du}{db} = 3 \\times 2 = \\bold{6} $$\n The derivative of $J$ with respect to $c$  $$ \\frac{dJ}{dc} = \\frac{dJ}{du}\\frac{du}{dc} = 3 \\times 3 = \\bold{9} $$\nGradient Descent for Logistic Regression #     Logistic regression recap\n$z = w^\\intercal +b$\n$\\hat{y} = \\hat{p} = \\sigma(z)$\n$L(\\hat{y}, y) = - \\Big[y\\log (a) + (1-y)\\log(1-\\hat{y})\\Big]$\n  Let\u0026rsquo;s say we have only two features, then we will have two weight and a bias.\nThe computation graph\n     The photo above uses $a$ for prediction $\\hat{y}$\n  Hence, we use $$dz = (a-y)$$ for calculating Loss function for single instance with respect to $$w_1$$ by calulating:\n$$ \\frac{dL}{dw_1} = \\frac{dL}{da}\\frac{da}{dz}\\frac{dz}{dw_1} = (a-y)(x_1) = \\bold{x_1\\frac{dL}{dz}} $$\nand with respect to $$w_2$$\n$$ \\frac{dL}{dw_2} = \\frac{dL}{da}\\frac{da}{dz}\\frac{dz}{dw_2} = (a-y)(x_2) = \\bold{x_2\\frac{dL}{dz}} $$\nfor bias it remains same:\n$$ \\frac{dL}{db} = \\bold{\\frac{dL}{dz}} $$\nThis makes the updates like this:\n$$ w_1 = w_1 - \\alpha dw_1\\\\ w_2 = w_2 = \\alpha dw_2\\\\b = b -\\alpha db $$\n where $dw_1, dw_2, db$ as said earlier represents the derivative of the final output variable (Loss function) with respect to respective variable.  Gradient Descent on $m$ Examples # This Loss function is for $m$ training examples computed over $(i)^\\text{th}$ instances.\n$$ J(w, b)=J(\\theta) = -\\frac{1}{m}\\sum^m_{i=1}\\bigg[y^{(i)}\\log\\Big(\\hat{y}^{(i)}\\Big)+ \\Big(1-y^{(i)}\\Big)\\log\\Big(1-\\hat{y}^{(i)}\\Big)\\bigg] $$\n where $$\\hat{y} = \\sigma(z^{(i)}) = \\sigma(w^\\intercal x^{(i)} + b)$$ is the prediction over one training example.  So for calculating Cost function derivative with respect to first weight becomes:\n$$ \\frac{\\partial J}{\\partial w_1} = \\frac{1}{m}\\sum^m_{i=1} \\frac{\\partial}{\\partial w_1}L(\\hat{y}^{(i)}, y^{(i)}) $$\nWhich as we have seen will then be:\n$$ \\frac{\\partial J}{\\partial w_1} = \\frac{1}{m}\\sum^m_{i=1} dw_1^{(i)} \\qquad\\qquad \\frac{\\partial J}{\\partial w_2} = \\frac{1}{m}\\sum^m_{i=1} dw_2^{(i)} $$\nWrap up in algorithm (what we can do) # Assuming we have only two features. The single step of gradient descent will look like:\n$j=0,\\; dw_1=0,\\; dw_2=0,\\; db=0\\\\\\text{For} \\enspace i=1\\enspace\\text{to}\\enspace m:$\n$\\qquad z^{(i)} = w^\\intercal x^{(i)} + b\\\\\\qquad \\hat{y}^{(i)} = \\sigma(z^{(i)})\\\\\\qquad J \\enspace+= -\\Big[y^{(i)}\\log\\hat{y}^{(i)}+ \\big(1-y^{(i)}\\big)\\log\\big(1-\\hat{y}^{(i)}\\big)]\\\\\\qquad dz^{(i)} = \\hat{y}^{(i)} - y^{(i)}\\\\\\qquad dw_1\\enspace += x_1^{(i)}dz^{(i)}\\enspace\\fcolorbox{red}{white}{here $dw_1$ is used as accumulator}\\\\\\qquad dw_2 \\enspace += x_2^{(i)}dz^{(i)}\\enspace\\fcolorbox{red}{white}{h ere $dw_2$ is used as accumulator}\\\\\\qquad db\\enspace+= dz^{(i)}$\n$J \\enspace/=m \\qquad\\fcolorbox{red}{white}{averaging cost function over $m$ training examples}\\\\dw_1\\enspace /=m; \\; dw_2\\enspace/=m\\; db\\enspace/=m\\\\w_1 = w_1 - \\alpha dw_1\\\\ w_2 = w_2 = \\alpha dw_2\\\\b = b -\\alpha db$\n We have a problem here in which we require two for loops:  One for iterating over $m$ training example. another one iterating over feature set calculating the derivative per feature.    Vectorization # Whenever possible, avoid explicit for-loops. Use vectorization.\nz = np.dot(w, x) + b  Vectorization relies on parallelization instructions called SIMD (Single Instruction Multiple Data), which can be be found in both CPU and GPU but GPUs are better at that.\n And that\u0026rsquo;s how we eliminate one for loop which was iterating over the features for calculating derivative and updating derivatives..\n    IMPORTANT\nAndrew refers to $dz = a (1-a)$\nNote that Andrew is using \u0026ldquo;$dz$\u0026rdquo; as a shorthand to refer to $\\frac{da}{dz} = a (1-a)$ .\nEarlier in this week\u0026rsquo;s videos, Andrew used the name \u0026ldquo;$dz$\u0026rdquo; to refer to a different derivative: $\\frac{dL}{dz} = a -y$.\nNote: here $a$ is $\\hat{y}$\n   Vectorizing Logistic Regression # We can make the prediction or the forward propagation step like this:\nStep 1 # $$ Z = [z^{(i)}, z^{(2)}, \u0026hellip;, z^{(m)}]= w^\\intercal X + [b, b, b, \u0026hellip;.b] $$\nwhere,\n $X$ represent the $(n_x, m)$ dimensional feature matrix. $[b, b, b, \u0026hellip;.b]$ is bias matrix with $(1, m)$ dimension.   In Python\nZ = np.dot(w.T, X) + b # here b is a real number which is broadcasted  Step 2 # $$ \\hat{Y} = [\\hat{y}^{(1)}, \\hat{y}^{(2)}, \u0026hellip;, \\hat{y}^{(m)}] = \\sigma(Z) $$\nVectorizing Logistic Regression\u0026rsquo;s Gradient Output # vectorizing calculation of \u0026ldquo;dz\u0026rdquo; ($\\frac{dL}{dz}$) # We want: $dz^{(1)} = [\\hat{y}^{(1)} - y^{(1)}]$, $dz^{(2)}= [\\hat{y}^{(2)} - y^{(2)}]$,\u0026hellip;\n$dZ = [dz^{(1)}, dz^{(2)}, \u0026hellip;, dz^{(m)}]$\nThen:\n$\\hat{Y} = [\\hat{y}^{(1)}, \u0026hellip;, \\hat{(m)}]$ $Y = [y^{(1)},\u0026hellip;, y^{(m)}]$\n$dZ = \\hat{Y} - Y$\nvectorizing updates of weights and bias # $dw = \\frac{1}{m}X{dZ}^\\intercal$\nWhich creates as ($n, 1$) dimensional vector with each element being from $dz_{(i)}$ to $dz_{(n)}$ where $n$ is the number of features.\ndw = (1/m)*np.dot(X, dZ.T)  $db = \\frac{1}{m} \\sum^m_{i=1} dz^{(i)}$\nwhich in python is done using\ndb = (1/m)*np.sum(dZ)  Implementing Logistic Regression # $Z = w^\\intercal X +b = \\text{np.dot(w.T, X)+b}$\n$\\hat{Y} = \\sigma(Z) $\n$dZ = \\hat{Y} - Y$\n$dw= \\frac{1}{m}XdZ^\\intercal$\n$db = \\frac{1}{m}\\text{ * np.sum($dZ$)}$\n$w = w -\\alpha dw$\n$b = b - \\alpha db$\nGeneral Principle of Broadcasting # If we have $(m, n)$ matrix and for any operation we want to do with $(1, n)$ or $(m, 1)$ matrix, the matrix with be converted to $(m, n)$ dimensional matrix by copying.\nIf we have $(m, 1)$ or $(1, m)$ matrix and for any operation we want to do with a real number $R$ get converted to $$(m, 1)$ or $(1, m)$ dimensional matrix by copying $R$.\nA note on python/NumPy vectors # import numpy as np a = np.random.randn(5) print(a) \u0026gt;\u0026gt;\u0026gt; [0.502, -0.296, 0.954, -0.821, -1.462] print(a.shape) \u0026gt;\u0026gt;\u0026gt;(5,)  Vectors like a are called rank 1 array in python. That is it is neither a row vector, nor a column vector. Which leads to some slightly non-intuitive effects such as-\nprint(a.T) \u0026gt;\u0026gt;\u0026gt; [0.502, -0.296, 0.954, -0.821, -1.462] print(np.dot(a, a.T) # should probanly be matrix product \u0026gt;\u0026gt;\u0026gt; 4.06570109321  Instead do this:\na = np.random.rand(5, 1) print(a) \u0026gt;\u0026gt;\u0026gt; [[-0.0967] [-2.3861] [-9.1231] [ 0.1231] [ 9.1111]]  assert(a.shape == (5, 1))  If you get a rank 1 array, just reshape it.\nSome important Points #  Softmax function  $$ \\text{for a matrix } x \\in \\mathbb{R}^{m \\times n} \\text{, $x_{ij}$ maps to the element in the $i^{th}$ row and $j^{th}$ column of $x$, thus we have: } $$\n $$ softmax(x) = softmax\\begin{bmatrix} x\\_{11} \u0026 x\\_{12} \u0026 x\\_{13} \u0026 \\dots \u0026 x\\_{1n} \\\\\\ x\\_{21} \u0026 x\\_{22} \u0026 x\\_{23} \u0026 \\dots \u0026 x\\_{2n} \\\\\\ \\vdots \u0026 \\vdots \u0026 \\vdots \u0026 \\ddots \u0026 \\vdots \\\\\\ x\\_{m1} \u0026 x\\_{m2} \u0026 x\\_{m3} \u0026 \\dots \u0026 x\\_{mn}\\end{bmatrix} \\\\[10pt]= \\begin{bmatrix} \\frac{e^{x\\_{11}}}{\\sum\\_{j}e^{x\\_{1j}}} \u0026 \\frac{e^{x\\_{12}}}{\\sum\\_{j}e^{x\\_{1j}}} \u0026 \\frac{e^{x\\_{13}}}{\\sum\\_{j}e^{x\\_{1j}}} \u0026 \\dots \u0026 \\frac{e^{x\\_{1n}}}{\\sum\\_{j}e^{x\\_{1j}}} \\\\\\ \\frac{e^{x\\_{21}}}{\\sum\\_{j}e^{x\\_{2j}}} \u0026 \\frac{e^{x\\_{22}}}{\\sum\\_{j}e^{x\\_{2j}}} \u0026 \\frac{e^{x\\_{23}}}{\\sum\\_{j}e^{x\\_{2j}}} \u0026 \\dots \u0026 \\frac{e^{x\\_{2n}}}{\\sum\\_{j}e^{x\\_{2j}}} \\\\\\ \\vdots \u0026 \\vdots \u0026 \\vdots \u0026 \\ddots \u0026 \\vdots \\\\\\ \\frac{e^{x\\_{m1}}}{\\sum\\_{j}e^{x\\_{mj}}} \u0026 \\frac{e^{x\\_{m2}}}{\\sum\\_{j}e^{x\\_{mj}}} \u0026 \\frac{e^{x\\_{m3}}}{\\sum\\_{j}e^{x\\_{mj}}} \u0026 \\dots \u0026 \\frac{e^{x\\_{mn}}}{\\sum\\_{j}e^{x\\_{mj}}}\\end{bmatrix} \\\\[10pt]= \\begin{pmatrix} softmax\\text{(first row of x)} \\\\\\ softmax\\text{(second row of x)} \\\\\\ ... \\\\\\ softmax\\text{(last row of x)} \\\\\\\\\\end{pmatrix} $$   L1 loss is defined as:  $$ \\begin{align*} \u0026amp; L_1(\\hat{y}, y) = \\sum_{i=0}^m|y^{(i)} - \\hat{y}^{(i)}| \\end{align*}\\tag{1} $$\n L2 loss is defined as:  $$ \\begin{align*} \u0026amp; L_2(\\hat{y},y) = \\sum_{i=0}^m(y^{(i)} - \\hat{y}^{(i)})^2 \\end{align*}\\tag{2} $$\nA trick when you want to flatten a matrix $X$ of shape $(a,b,c,d)$ to a matrix $X_flatten$ of shape $(b∗c∗d, a)$ is to use:\nX_flatten = X.reshape(X.shape[0],-1).T  "}).add({id:2,href:"/ml/intro_dl/neural-networks/week3/",title:"Week 3 — One hidden layer Neural Networks",description:"Computation inside neural networks and activation functions",content:"May 4, 2021\nShallow Neural Network # Neural Networks Overview #   Note: For new notation\nWe\u0026rsquo;ll use superscript square bracket one to refer to quantities associated with a particular layer.     Neural Network Representation # The term hidden layer refers to the fact that in the training set, for these nodes in the middle (the hidden layer neurons) are not observed.\n Source: Wikipedia. Used for representation only.\n  The term $a$ also stands for the activations, we will use it for denoting the outputs/activations of a layer that the layer is passing on to the subsequent layers.\n  Input layer is passing activations $a^{[0]}$ to the hidden layer (which we previously denoting by $X$.\n  The hidden layer will in turn generate its own activations $a^{[1]}$\n  Which is a four dimensional vector b/c the hidden layer has four neurons\n $$ a^{[1]} = \\begin{bmatrix}a^{[1]}_1\\\\[5pt] a^{[1]}_2\\\\[5pt]a^{[1]}_3\\\\[5pt]a^{[1]}_4\\end{bmatrix} $$      The output layer generates some value $a^{[2]}$ which is just a real number $\\hat{y}$.\n   2 layer NN: We don\u0026rsquo;t count the \u0026lsquo;input layer\u0026rsquo;\n   The parameter associated with the layers will also be denoted with Superscript notations like $W^{[1]}$, $b^{[1]}$. Here,  $W^{[1]}$ will be $(4. 3)$ dimensional vector for $(\\text{noOfNeuronsInCurrentLayer},\\text{ noOfNeuronsInPreviviousLayer})$ with each value associated with the connection weights.   $b^{[1]}$ will be $(4, 1)$ dimensional vector, only stores biases for number of neurons in current layer.    Computing a Neural Network\u0026rsquo;s Output #  This is what logistic regression does. A NN is composed bunch of neurons which performs the same operation (With the activation function different if required other than sigmoid, most popular being ReLU)\n  Let\u0026rsquo;s go a little deeper:\n The first neuron of the hidden layer we just saw earlier gets all inputs from input layer (and so does other neurons in hidden layer)   It computes\n $$ z^{[1]}_1 = w^{[1]}_1 X + b_1^{[1]}\\\\[10pt] a^{[1]}_1 = \\sigma(z^{[1]}_1) $$  where,\n $$ a^{[1](m)\\rightarrow \\text{ 1st neuron and m$^{th}$ training example}}_{l\\rightarrow \\text{node in layer l}} $$      The second neuron computes,  $$ z^{[1]}_2 = w^{[1]}_2 X + b^{[1]}_2\\\\[10pt] a^{[1]}_2 = \\sigma(z^{[1]}_2) $$   and so does other neurons in the layer.   Once again writing all equations:\n$$ z^{[1]}_1 = w^{[1]}_1 X + b_1^{[1]}, \\qquad a^{[1]}_1 = \\sigma(z^{[1]}_1)\\tag{1} $$\n$$ z^{[1]}_2 = w^{[1]}_2 X + b_2^{[1]}, \\qquad a^{[1]}_2 = \\sigma(z^{[1]}_2) \\tag{2} $$\n$$ z^{[1]}_3 = w^{[1]}_3 X + b_3^{[1]}, \\qquad a^{[1]}_3 = \\sigma(z^{[1]}_3) \\tag{3} $$\n$$ z^{[1]}_4 = w^{[1]}_4 X + b_4^{[1]}, \\qquad a^{[1]}_4 = \\sigma(z^{[1]}_4) \\tag{4} $$\nTo vectorize we can do like this: #  $$ \\overbrace{\\begin{bmatrix}--w^{[1]\\bold{\\top}}_1--\\\\--w^{[1]\\bold{\\top}}_2--\\\\--w^{[1]\\bold{\\top}}_3--\\\\--w^{[1]\\bold{\\top}}_4--\\end{bmatrix}}^{W^{[1]}} \\begin{bmatrix}x_1\\\\x_2\\\\x_3\\end{bmatrix} +\\overbrace{\\begin{bmatrix}b^{[1]}_1\\\\b^{[1]}_2\\\\b^{[1]}_3\\\\b^{[1]}_4\\end{bmatrix}}^{b^{[1]}} =\\begin{bmatrix}w^{[1]\\bold{\\top}}_1X + b^{[1]}_1\\\\w^{[1]\\bold{\\top}}_2X + b^{[1]}_2\\\\w^{[1]\\bold{\\top}}_3X + b^{[1]}_3\\\\w^{[1]\\bold{\\top}}_4X + b^{[1]}_4\\end{bmatrix} = \\overbrace{\\begin{bmatrix}z^{[1]}_1\\\\z^{[1]}_2\\\\z^{[1]}_3\\\\z^{[1]}_4\\end{bmatrix}}^{Z^{[1]}} $$   $$ \\overbrace{ \\begin{bmatrix}a^{[1]}_1\\\\ a^{[1]}_2\\\\a^{[1]}_3\\\\ a^{[1]}_4\\end{bmatrix}}^{a^{[1]}}= \\sigma(Z^{[1]}) $$  Give input $X = a^{[0]}$, then\n$z^{[1]} = W^{[1]}a^{[0]} + b^{[1]}$\n$a^{[1]} = \\sigma(z^{[1]})$\n$z^{[1]} = W^{[2]}a^{[1]} + b ^{[2]}$\n$a^{[2]} = \\sigma(z^{[2]})$\nWhere $W^{[2]}$ is $(1, 4)$ and $a^{[1]}$ is $(4, 1)$ dimensional matrices.\nVectorizing across multiple examples # If we have defined a neural network like this:\n for i=1 to m:\n$z^{[1](i)} = W^{[1]}a^{[0](i)} + b^{[1]}$ $a^{[1](i)} = \\sigma(z^{[1](i)})$ $z^{[2](i)} = W^{[2]}a^{[1](i)} + b ^{[2]}$ $a^{[2](i)} = \\sigma(z^{[2](i)})$ then for $m$ training examples we need,\n $$ X \\rightarrow a^{[2]} = \\hat{y}\\\\X^{(1)} \\rightarrow a^{[2](1)} = \\hat{y}^{(1)}\\\\X^{(2)} \\rightarrow a^{[2](2)} = \\hat{y}^{(2)}\\\\...\\\\X^{(1)} \\rightarrow a^{[2](m)} = \\hat{y}^{m)} $$  we can vectorize over $m$ training examples as: #  $$ Z^{[1]} = W^{[1]}X + b^{[1]}\\\\A^{[1]} = \\sigma(Z^{[1]})\\\\Z^{[2]} = W^{[2]}A^{[1]} + b ^{[2]}\\\\A^{[2]} = \\sigma(Z^{[2]}) $$   These matrices is corresponds to a single hidden layer.\n  A good thing about these matrices $(Z, A)$ is that they represent vertically hidden units and horizontally they represent training examples.\n That means first row first column represent output from first hidden unit for first training example. The second in the first row output of same first hidden unit for second training example. Vertically you get output from second, third and so on hidden unit for the training examples.  Explanation for Vectorized Implementation #   Activation Functions # In real world NN, instead of using $\\sigma$ (sigmoid) activation function for every problem, we can use other activation functions. So in general we replace $\\sigma(z^{[\\mathbb{R}]})$ with $g(z^{[\\mathbb{R}]})$\nThe problem with $\\tanh$ $\\big(tanh(z) = 2\\sigma(2z) -1\\big)$ or $\\sigma$ (sigmoid) function is that when inputs become large, the function saturates at -1 or 1/ 0 or 1 respectively, with derivative extremely close to zero. Thus for backpropagation there is no gradients to work with.\nOne of the very commonly used Activation function is\nRectified Linear Unit (ReLU) # $$ ReLU(z) = \\max(0, z) $$\n Source: Wikipedia\n  This function is continuous but unfortunately not differentiable at $z=0$ as slope changes abruptly and its derivative is zero for $z\u0026lt;0$. But is practice, it works really well.\nBut might suffer from dying ReLUs, i.e., that is some neurons stop outputting anything other than 0. In that case Leaky ReLUs and its variant but be better choice.\nLeaky ReLU # $$ \\text{Leaky ReLU}_\\alpha(z) = \\max(\\alpha z. z) $$\n$\\alpha$ defines the slope of the function for $z\u0026lt;0$, that is how much it should \u0026ldquo;leak.\n Source: Wikipedia\n  This small slope ensures that the neurons never really \u0026ldquo;die\u0026rdquo;.\nWhy do you need non-linear activation functions? # If your activation function is linear then,\n the entire neural network simplifies down to a single neuron, since the hidden neurons don’t do any ‘processing’, they just pass on their z values to the next layer, which essentially is like applying a different set of weights and running a single neuron.  Derivatives of Activation Functions # We often use $g'(z)$ to represent the derivative of a function with input $z$ with respect to $z$ i.e., $\\frac{d}{dz}g(z) = g'(z)$\nDerivative of Sigmoid # $$ g'(z) = \\frac{d}{dz}g(z) = g(z)\\big(1-g(z)\\big) $$\nfor $z=10$, $g(z) \\approx1$ | $g'(z)=1(1-1)\\approx0$\nfor $z=-10$, $g(z)\\approx0$ | $g'(z)\\approx0.(1-0) \\approx0$\nfor $z=0$, $g(z)=\\frac{1}{2}$ | $g'(z)=\\frac{1}{2}(1-\\frac{1}{2}) = \\frac{1}{4}$\nDerivative of $\\tanh$ # $$ g'(z) = 1-\\bigg(tanh(z)\\bigg)^2 $$\nfor $z=10$, $g(z) \\approx1$ | $g'(z)=1(1-1)\\approx0$\nfor $z=-10$, $g(z)\\approx-1$ | $g'(z)\\approx0$\nfor $z=0$, $g(z)=0$ | $g'(z)=1$\nDerivative of ReLU #  $$ g'(x) = \\begin{cases}0\u0026\\text{if } zif $z=0$, It might be undefined but will still work when implementing, you could set the derivative to be 0 or 1, it doesn\u0026rsquo;t matter.\nLeaky ReLU #  $$ g'(z)=\\begin{cases}\\alpha \u0026\\text{if } z0\\\\1 \u0026\\text{if }z\\geqslant0\\end{cases} $$  Gradient Descent for Neural Networks (2 layer, 1 hidden) # Parameters: # $W^{[1]}, b^{[1]}, W^{[2]}, b^{[2]}$\n$n_x=n^{[0]}, n^{[1]}, n^{[2]}=1$\nWhere,\n $W^{[1]}$ is $(n^{[1]}, n^{[0]})$ dimensional matrix $W^{[2]}$ is $(n^{[2]}, n^{[1]})$ dimensional matrix $b^{[1]}$ is $(n^{[1]}, 1)$ dimensional matrix $b^{[2]}$ is $(n^{[2]}, 1)$ dimensional matrix  Cost Function # $$ J(W^{[1]}, b^{[1]}, W^{[2]}, b^{[2]}) = \\frac{1}{m}\\sum^m_{i=1}L(\\hat{y}, y) $$\nWhere,\n $\\hat{y}$ is $a^{[2]}$  Gradient Descent # When training a neural network it is important to initialize the parameters randomly rather than to all zeros.\n $\\text{Repeat\\{}$  $\\text{Compute the prediction} (\\hat{y}^{[i]}, i=1\u0026hellip;m)$\n$dW^{[1]}=\\frac{dJ}{dW^{[1]}}$, $db^{[1]} = \\frac{dJ}{db^{[1]}}$, $\u0026hellip;$\n$W^{[1]} =W^{[1]} - \\alpha dW^{[1]}$\n$b^{[1]} = b^{[1]} - \\alpha db^{[1]}$\n$W^{[1]} = W^{[2]} - \\alpha dW^{[2]}$\n$b^{[2]} = b^{[2]} - \\alpha db^{[2]}$\n$\\}$\nFormulas for computing derivatives (assuming for binary classification) # Forward Propagation\n $$ Z^{[1]} = W^{[1]}X + b^{[1]}\\\\ A^{[1]} = \\sigma(Z^{[1]})\\\\ Z^{[2]} = W^{[2]}A^{[1]} + b ^{[2]}\\\\ A^{[2]}=\\hat{Y}^{[2]} = g^{[1]}(Z^{[2]})=\\sigma(Z^{[2]}) $$  Back Propagation\n$dZ^{[2]} = A^{[2]} - Y$\n$dW^{[2]} = \\frac{1}{m}dZ^{[2]}A^{[1]\\bold{\\top}}$\n$db^{[2]} = \\frac{1}{m}\\text{ np.sum($dZ^{[2]}$, axis=1, keepdims=True)}\\;\\fcolorbox{red}{white}{avoids 1 rank matrix}$\n$dZ^{[1]} = W^{[2]\\bold{\\top}} dZ^{[2]} * g'^{[1]}(Z^{[1]})$\n$dW^{[1]} = \\frac{1}{m} dZ^{[1]}X^\\bold{\\top}$\n$db^{[1]} = \\frac{1}{m}\\text{np.sum($dZ^{[1]}$, axis=1, keepdims=True})$\nWhere,\n $g'^{[1]}(Z^{[1]})$ is $(1-\\text{np.power($A^{[1]}$},, 2)$  Backpropagation intuition (optional) #   Please note that in the this video at 8:20, the text should be \u0026ldquo;$dw^{[1]}$\u0026rdquo; instead of \u0026ldquo;$dw^{[2]}$\u0026rdquo;.      Random Initialization # If two hidden units with the same activation function are connected to the same inputs, then these units must have different initial parameters. If they have the same initial parameters, then a deterministic learning algorithm applied to a deterministic cost and model will constantly update both of these units in the same way.\nThis helps in breaking symmetry and every neuron is no longer performing the same computation.\n$W^{[1]} = \\text{np.random.randn((2, 2)) * 0.01}$\n$b^{[1]} = \\text{np.zero((2, 1))}$\nWe need to initialize the weights to a very small value, as when\n During forward propagation calculating $Z$ with become very big and hence increasing the output of activation function (for $\\sigma$ or $\\tanh$) thus saturating the function and slowing down learning.  If we don\u0026rsquo;t have these functions throughout our NN, it\u0026rsquo;s less of an issue.\nBut for binary classification this might be required for output layer.\n"}).add({id:3,href:"/ml/intro_dl/neural-networks/week4/",title:"Week 4 — L Layers Deep Neural Networks",description:"Computation of L layered neural network",content:"May 6, 2021\n  New notations introduces\n  $L$ to denote the number of layers in the network\nIn previous week example $L = 2$\n  $n^{[l]}$ to denote the number of units/neurons in the layer $l$\n  In previous week example $n^{[1]} = 4, , n^{[0]} = n_x = 3$\n   Forward Propagation in a Deep Network # Let\u0026rsquo;s go over what forward propagation will look like for a single training example $x$ (which is also $a^{[0]}$).\n $z^{[1]} = W^{[1]}a^{[0]}+b^{[1]}$\n$a^{[1]} = g^{[1]}(z^{[1]})$\n$z^{[2]} = W^{[2]}a^{[1]}+b^{[2]}$\n$a^{[2]} = g^{[2]}(z^{[2]})$\n$\\qquad\u0026hellip;.$\n$z^{[4]} = W^{[4]}a^{[3]} + b^{[4]}$\n$a^{[4]} = \\hat{y} = g^{[4]}(z^{[4]})$\nGenerally equation for the forward propagation of any layer $l$ #  $$ z^{[l]} = W^{[l]}a^{[l-1]} + b^{[l]} \\\\[5pt] a^{[l]} = g^{[l]}(z^{[l]}) $$  Vectorizing over whole training set or $m$ training example #  $$ Z^{[l]} = W^{[l]}A^{[l-1]} + b^{[l]}\\\\[5pt] A^{[l]} = g^{[l]}(Z^{[l]}) $$  Here $A^{[0]}$ is going to be $X$.\nGetting your matrix dimensions right #   In the this video, at time 6:35, the correct formula should be:\n$a^{[l]} = g^{[l]}(z^{[l]})$\n   Note that \u0026ldquo;a\u0026rdquo; and \u0026ldquo;z have dimensions $(n^{[l]},1)$.\n Check the dimension of the matrix $W^{[l]}$ as to be $(n^{[l]}, n^{[l-1]})$ and dimension of $X$ or $A^{[0]}$ to be $(n^{[0]}, m)$. The dimension of the matrix $b^{[l]}$ to be $(n^{[l]},1)$ The dimension of $Z^{[l]}$ and $A^{[l]}$ to be $(n^{[l]}, m)$ The dimension of $dW^{[l]}$ be $(n^{[l]}, n^{[l-1]})$. The dimension of $db^{[l]}$ be $(n^{[l]}, 1)$ The dimension of $dZ^{[l]}$ and $dA^{[l]}$ be $(n^{[l]}, m )$.  Why deep representations? # Deep representations help in generating lower level features which can then be used to build and then composing these features in later layer of NN to create higher level features and understand complex functions.\nCircuit theory and deep learning # Informally: There are functions you can compute with a \u0026ldquo;small\u0026rdquo; L-layer deep neural network that shallower networks require exponentially more hidden units to compute.\nBuilding blocks of deep neural networks # We have already seen the forward propagation for the $L$ layers neural network in which we cached $Z^{[l]}$.\nThe the backward step would be like to calculate $dA^{[l-1]},\\enspace dZ^{[l]},\\enspace dW^{[l]}.\\enspace db^{[l]}$ with input as cache and $dA^{[l]}$.\n Forward and Backward Propagation # {% hint style=\u0026ldquo;warning\u0026rdquo; %} Note that in the next video at 2:30, the text that\u0026rsquo;s written should be $dw^{[l]} = dz^{[l]} * a^{[l-1]\\bold{\\top}}$ {% endhint %}\n Forward and backward propagation. Source: Coursera Assignment\n  To output $dA^{[l-1]},\\enspace dZ^{[l]},\\enspace dW^{[l]}.\\enspace db^{[l]}$; we do:\n$dZ^{[l]} = dA^{[l]}* g'^{[l]}(Z^{[l]})$\n$dW^{[l]}=\\frac{1}{m}dZ^{[l]}.A^{[l-1]\\bold{\\top}}$\n$db^{[l]}=\\frac{1}{m}\\text{np.sum($dZ^{[l]}$, axis=1, keepdims=True)}$\n$dA^{[l-1]}=W^{[l]\\bold{\\top}}dZ^{[l]}$\n$dAL = -(\\text{np.divide($Y, AL$)} - \\text{np.divide($1-Y$, $1-AL$)}$\nParameters VS Hyperparameters # Parameters are values that the neural net needs to learn by itself such as $W$ and $b$.\nHyperparameters are the extra values we decide and that we give it that it needs to run - the learning rate, the number of iterations of gradient descent, the number of hidden layers, the number of hidden units in each layer, and the choice of activation function.\nWe call these hyperparameters since these influence the actual parameters that the neural net is responsible for calculating.\n"}).add({id:4,href:"/ml/intro_dl/",title:"Intro to DL",description:"",content:""}).add({id:5,href:"/ml/intro_dl/neural-networks/",title:"Neural Networks and Deep Learning",description:"",content:""}).add({id:6,href:"/ml/",title:"Docs",description:"",content:""}),search.addEventListener('input',b,!0);function b(){var b,e;const d=5;b=this.value,e=a.search(b,{limit:d,enrich:!0});const c=new Map;for(const a of e.flatMap(a=>a.result)){if(c.has(a.doc.href))continue;c.set(a.doc.href,a.doc)}if(suggestions.innerHTML="",suggestions.classList.remove('d-none'),c.size===0&&b){const a=document.createElement('div');a.innerHTML=`No results for "<strong>${b}</strong>"`,a.classList.add("suggestion__no-results"),suggestions.appendChild(a);return}for(const[h,g]of c){const b=document.createElement('div');suggestions.appendChild(b);const a=document.createElement('a');a.href=h,b.appendChild(a);const e=document.createElement('span');e.textContent=g.title,e.classList.add("suggestion__title"),a.appendChild(e);const f=document.createElement('span');if(f.textContent=g.description,f.classList.add("suggestion__description"),a.appendChild(f),suggestions.appendChild(b),suggestions.childElementCount==d)break}}})()